import{_ as e,o as r,c as a,ag as s}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Software","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/software.md","filePath":"theory/systems/software.md"}'),o={name:"theory/systems/software.md"};function n(i,t,d,l,c,p){return r(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="software" tabindex="-1">Software <a class="header-anchor" href="#software" aria-label="Permalink to &quot;Software&quot;">​</a></h1><p>Hardware is useless without software to run on it. Software is the set of instructions — programs — that tell a computer what to do. Every program you use, from a browser to Delphi, is software.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>The software classification system (System vs Application) is introduced in Grade 10. Operating system types and utility software extend into Grade 11.</p></div><hr><h2 id="hardware-vs-software" tabindex="-1">Hardware vs Software <a class="header-anchor" href="#hardware-vs-software" aria-label="Permalink to &quot;Hardware vs Software&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Hardware</th><th>Software</th></tr></thead><tbody><tr><td>Definition</td><td>Physical components you can touch</td><td>Programs and instructions</td></tr><tr><td>Examples</td><td>CPU, RAM, hard drive, monitor</td><td>Windows, MS Word, Delphi, VLC</td></tr><tr><td>Change</td><td>Requires physical replacement</td><td>Updated or replaced via download/install</td></tr><tr><td>Stored</td><td>In circuit boards, chips, storage</td><td>On storage devices (HDD/SSD) or ROM</td></tr></tbody></table><hr><h2 id="software-categories" tabindex="-1">Software Categories <a class="header-anchor" href="#software-categories" aria-label="Permalink to &quot;Software Categories&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SOFTWARE</span></span>
<span class="line"><span>├── System Software</span></span>
<span class="line"><span>│   ├── Operating System (OS)</span></span>
<span class="line"><span>│   ├── Utility Software</span></span>
<span class="line"><span>│   └── Device Drivers</span></span>
<span class="line"><span>└── Application Software</span></span>
<span class="line"><span>    ├── General Purpose</span></span>
<span class="line"><span>    ├── Specific Purpose</span></span>
<span class="line"><span>    └── Custom-Written</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="system-software" tabindex="-1">System Software <a class="header-anchor" href="#system-software" aria-label="Permalink to &quot;System Software&quot;">​</a></h2><p>System software manages the computer&#39;s hardware and provides a platform for application software to run. Users rarely interact with it directly.</p><h3 id="operating-system-os" tabindex="-1">Operating System (OS) <a class="header-anchor" href="#operating-system-os" aria-label="Permalink to &quot;Operating System (OS)&quot;">​</a></h3><p>The <strong>OS</strong> is the most important piece of system software. It is the bridge between the user, the applications, and the hardware.</p><p><strong>Core functions of an OS:</strong></p><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td><strong>Process management</strong></td><td>Controls which programs run and when; manages CPU time</td></tr><tr><td><strong>Memory management</strong></td><td>Allocates RAM to programs; manages virtual memory</td></tr><tr><td><strong>File management</strong></td><td>Organises files in folders; handles read/write operations</td></tr><tr><td><strong>Device management</strong></td><td>Communicates with hardware via device drivers</td></tr><tr><td><strong>Security</strong></td><td>User accounts, passwords, access rights, firewalls</td></tr><tr><td><strong>User interface</strong></td><td>GUI or CLI for the user to interact with the system</td></tr></tbody></table><p><strong>Types of Operating System:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>GUI (Graphical User Interface)</strong></td><td>Uses icons, windows, mouse — visual interaction</td><td>Windows 11, macOS, Ubuntu</td></tr><tr><td><strong>CLI (Command Line Interface)</strong></td><td>Text commands only — no mouse</td><td>MS-DOS, Linux terminal, PowerShell</td></tr><tr><td><strong>Multi-user</strong></td><td>Multiple users can work simultaneously</td><td>Linux servers, mainframes</td></tr><tr><td><strong>Multi-tasking</strong></td><td>Multiple programs run at the same time</td><td>Windows, macOS</td></tr><tr><td><strong>Real-time OS (RTOS)</strong></td><td>Processes data instantly with no delay</td><td>Medical equipment, aircraft, factory robots</td></tr><tr><td><strong>Embedded OS</strong></td><td>Built into a device; dedicated function</td><td>Smart TV OS, washing machine controller</td></tr><tr><td><strong>Mobile OS</strong></td><td>Designed for touchscreen portable devices</td><td>Android, iOS</td></tr><tr><td><strong>Network OS (NOS)</strong></td><td>Manages network resources, shared access</td><td>Windows Server, Novell NetWare</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Grade 11 — Extension</p><p>At Grade 11, you need to compare OS types in terms of: usability (GUI easier than CLI), security (CLI can be more secure), resources needed (CLI uses less RAM), and use cases (CLI for servers, GUI for desktops).</p></div><div class="important custom-block github-alert"><p class="custom-block-title">Grade 12 — Mastery</p><p>At Grade 12, understand how OS interacts with virtualisation (running multiple OS instances on one physical machine) and cloud-based OS delivery.</p></div><hr><h3 id="utility-software" tabindex="-1">Utility Software <a class="header-anchor" href="#utility-software" aria-label="Permalink to &quot;Utility Software&quot;">​</a></h3><p>Utility programs maintain, optimise, and protect the computer system. They work in the background or on demand.</p><table tabindex="0"><thead><tr><th>Utility</th><th>Function</th><th>Example</th></tr></thead><tbody><tr><td><strong>Antivirus</strong></td><td>Detect and remove malware</td><td>Avast, Windows Defender, Kaspersky</td></tr><tr><td><strong>Firewall</strong></td><td>Monitor and filter network traffic</td><td>Windows Firewall, hardware firewalls</td></tr><tr><td><strong>Backup software</strong></td><td>Create copies of data for recovery</td><td>Windows Backup, Time Machine</td></tr><tr><td><strong>Disk cleanup</strong></td><td>Remove unnecessary files to free space</td><td>Windows Disk Cleanup, CCleaner</td></tr><tr><td><strong>Disk defragmenter</strong></td><td>Rearrange fragmented files on HDD for faster access</td><td>Windows Defragmenter</td></tr><tr><td><strong>Compression software</strong></td><td>Reduce file size for storage/transfer</td><td>WinZip, 7-Zip, Windows built-in</td></tr><tr><td><strong>File manager</strong></td><td>Browse, copy, move, organise files</td><td>Windows Explorer, Finder</td></tr><tr><td><strong>Task manager</strong></td><td>Monitor and control running processes</td><td>Windows Task Manager</td></tr><tr><td><strong>Screensaver / Power mgmt</strong></td><td>Save energy when computer is idle</td><td>Windows power settings</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Disk Defragmenter vs SSD</p><p>Defragmentation is only useful on HDDs (spinning disks). SSDs do NOT need defragmentation — it actually shortens their lifespan. Modern Windows automatically skips defrag on SSDs.</p></div><hr><h3 id="device-drivers" tabindex="-1">Device Drivers <a class="header-anchor" href="#device-drivers" aria-label="Permalink to &quot;Device Drivers&quot;">​</a></h3><p>A <strong>device driver</strong> is a small program that allows the OS to communicate with a specific hardware device.</p><ul><li>Every hardware device needs a driver: printer, graphics card, keyboard, webcam</li><li>When you plug in a new device, Windows searches for the correct driver</li><li>Outdated or missing drivers cause device malfunction</li></ul><hr><h2 id="application-software" tabindex="-1">Application Software <a class="header-anchor" href="#application-software" aria-label="Permalink to &quot;Application Software&quot;">​</a></h2><p>Application software is designed for end users to perform specific tasks.</p><h3 id="general-purpose-applications" tabindex="-1">General Purpose Applications <a class="header-anchor" href="#general-purpose-applications" aria-label="Permalink to &quot;General Purpose Applications&quot;">​</a></h3><p>Can be used for many different tasks — not tied to one job:</p><table tabindex="0"><thead><tr><th>Software</th><th>Type</th><th>Use</th></tr></thead><tbody><tr><td>Microsoft Word</td><td>Word processor</td><td>Create and edit text documents</td></tr><tr><td>Microsoft Excel</td><td>Spreadsheet</td><td>Calculations, data analysis, charts</td></tr><tr><td>Microsoft PowerPoint</td><td>Presentation</td><td>Slideshows, visual presentations</td></tr><tr><td>Google Chrome / Firefox</td><td>Web browser</td><td>Browse the internet</td></tr><tr><td>VLC Media Player</td><td>Media player</td><td>Play audio and video files</td></tr></tbody></table><h3 id="specific-purpose-applications" tabindex="-1">Specific Purpose Applications <a class="header-anchor" href="#specific-purpose-applications" aria-label="Permalink to &quot;Specific Purpose Applications&quot;">​</a></h3><p>Designed for one particular type of task:</p><table tabindex="0"><thead><tr><th>Software</th><th>Use</th></tr></thead><tbody><tr><td>Delphi / Visual Studio</td><td>Software development / coding</td></tr><tr><td>Adobe Photoshop</td><td>Image editing</td></tr><tr><td>AutoCAD</td><td>Engineering / architectural drawing</td></tr><tr><td>Sage Accounting</td><td>Business accounting</td></tr><tr><td>MS Project</td><td>Project management</td></tr></tbody></table><h3 id="custom-written-applications" tabindex="-1">Custom-Written Applications <a class="header-anchor" href="#custom-written-applications" aria-label="Permalink to &quot;Custom-Written Applications&quot;">​</a></h3><p>Software written specifically for ONE organisation&#39;s unique needs:</p><ul><li><strong>Example:</strong> A hospital patient management system built exactly to that hospital&#39;s workflows</li><li>More expensive than off-the-shelf, but perfectly suited to the organisation</li><li>Maintained by the company or contracted developers</li></ul><hr><h2 id="software-licensing" tabindex="-1">Software Licensing <a class="header-anchor" href="#software-licensing" aria-label="Permalink to &quot;Software Licensing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Licence Type</th><th>Cost</th><th>Restrictions</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Proprietary / Commercial</strong></td><td>Paid</td><td>Cannot copy, modify, or distribute</td><td>Microsoft Office, Adobe CC</td></tr><tr><td><strong>Freeware</strong></td><td>Free</td><td>Can use freely; cannot modify source</td><td>VLC, 7-Zip</td></tr><tr><td><strong>Shareware</strong></td><td>Free trial</td><td>Pay to continue after trial</td><td>WinZip (trial)</td></tr><tr><td><strong>Open source</strong></td><td>Free</td><td>Source code available; can modify and distribute</td><td>Linux, Firefox, LibreOffice</td></tr><tr><td><strong>Creative Commons</strong></td><td>Varies</td><td>Specific conditions set by the creator</td><td>Many online images and music</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Open Source ≠ Free</p><p>Open source means the source code is available — some open source software has commercial licences. &quot;Free&quot; can mean free as in cost (freeware) or free as in freedom (open source). These are different things.</p></div><hr><h2 id="foss-—-free-and-open-source-software" tabindex="-1">FOSS — Free and Open Source Software <a class="header-anchor" href="#foss-—-free-and-open-source-software" aria-label="Permalink to &quot;FOSS — Free and Open Source Software&quot;">​</a></h2><p><strong>FOSS</strong> combines free (no cost) and open source (modifiable source code):</p><ul><li>Linux operating system</li><li>LibreOffice (alternative to MS Office)</li><li>Firefox, Chromium</li><li>Python, PHP, MySQL</li></ul><p><strong>Advantages of FOSS:</strong></p><ul><li>No cost</li><li>Community-supported</li><li>Transparent — anyone can inspect the code for security flaws</li><li>Customisable</li></ul><p><strong>Disadvantages:</strong></p><ul><li>Less formal support (community forums vs paid helpdesk)</li><li>Compatibility issues with proprietary software</li><li>Can be less polished than commercial alternatives</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Software</strong></td><td>Programs and operating information used by a computer</td></tr><tr><td><strong>System software</strong></td><td>Software that manages hardware and provides a platform for applications</td></tr><tr><td><strong>Operating system</strong></td><td>Core system software managing all computer resources</td></tr><tr><td><strong>GUI</strong></td><td>Graphical User Interface — visual icons, windows, mouse-driven</td></tr><tr><td><strong>CLI</strong></td><td>Command Line Interface — text commands only</td></tr><tr><td><strong>Utility software</strong></td><td>Programs that maintain and optimise the computer system</td></tr><tr><td><strong>Device driver</strong></td><td>Software enabling the OS to communicate with a hardware device</td></tr><tr><td><strong>Application software</strong></td><td>Software for end-user tasks</td></tr><tr><td><strong>Freeware</strong></td><td>Free-to-use software (source code not necessarily available)</td></tr><tr><td><strong>Open source</strong></td><td>Software with publicly available, modifiable source code</td></tr><tr><td><strong>FOSS</strong></td><td>Free and Open Source Software</td></tr><tr><td><strong>Proprietary</strong></td><td>Commercially licensed software — owned by a company</td></tr><tr><td><strong>Custom software</strong></td><td>Software built for one specific organisation&#39;s needs</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Classify the following as system or application software and give a reason&quot;</strong> (2 marks each)<br> → Know: OS + utilities = system; everything else users run = application</p></li><li><p><strong>&quot;Name TWO types of application software and give an example of each&quot;</strong> (4 marks)<br> → General purpose (Word), Specific purpose (Photoshop), Custom-written</p></li><li><p><strong>&quot;Explain the difference between freeware and open source&quot;</strong> (2–3 marks)<br> → Freeware = free to use but closed source; open source = source code available, can modify</p></li><li><p><strong>&quot;Give TWO functions of an operating system&quot;</strong> (4 marks)<br> → Always name the function AND explain what it does in that computer context</p></li><li><p><strong>&quot;Why would a server use a CLI rather than a GUI?&quot;</strong> (2 marks)<br> → CLI uses less RAM/processing power; better for remote administration; more efficient for experienced users</p></li></ol></div>`,59)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
